'use strict';

// Microsoft Graph helper — app-only (client-credentials) token + user photo fetch.
// House HTTP client is axios (see helpers/brevo.js etc.).
const axios = require('axios');
const graph = require('../config/graph.config');

// Cached app token: { token, expiresAt(ms) }. Graph tokens last ~1h; we refresh
// a minute early. Module-scoped so it is shared across requests in the process.
let cachedToken = null;

/**
 * Acquire (and cache) an app-only Graph access token via client_credentials.
 * Returns null if Graph isn't configured. Throws on a genuine HTTP error so the
 * caller can decide how to handle it.
 */
async function getAppToken() {
  if (!graph.isConfigured) return null;

  const now = Date.now();
  if (cachedToken && cachedToken.expiresAt > now + 60_000) {
    return cachedToken.token;
  }

  const url = `https://login.microsoftonline.com/${graph.TENANT_ID}/oauth2/v2.0/token`;
  const body = new URLSearchParams({
    client_id: graph.CLIENT_ID,
    client_secret: graph.CLIENT_SECRET,
    scope: 'https://graph.microsoft.com/.default',
    grant_type: 'client_credentials',
  });

  const { data } = await axios.post(url, body.toString(), {
    headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
  });

  cachedToken = {
    token: data.access_token,
    expiresAt: now + (Number(data.expires_in) || 3600) * 1000,
  };
  return cachedToken.token;
}

/**
 * Fetch a user's M365/Teams profile photo by email (their UPN).
 * Returns { buffer, contentType } or null when the user has no photo (404),
 * Graph isn't configured, or any error occurs. Never throws.
 */
async function fetchUserPhoto(email) {
  if (!graph.isConfigured || !email) return null;

  let token;
  try {
    token = await getAppToken();
  } catch (err) {
    console.warn('Graph: token acquisition failed:', err.response?.status || err.message);
    return null;
  }
  if (!token) return null;

  const url = `https://graph.microsoft.com/v1.0/users/${encodeURIComponent(email)}/photo/$value`;
  try {
    const res = await axios.get(url, {
      headers: { Authorization: `Bearer ${token}` },
      responseType: 'arraybuffer',
    });
    return {
      buffer: Buffer.from(res.data),
      contentType: res.headers['content-type'] || 'image/jpeg',
    };
  } catch (err) {
    // 404 simply means the user hasn't set a photo — expected, not an error worth logging.
    const status = err.response?.status;
    if (status !== 404) {
      console.warn(`Graph: photo fetch failed for ${email}:`, status || err.message);
    }
    return null;
  }
}

// Exposed for tests to reset the module-scoped token cache between cases.
function _resetTokenCache() { cachedToken = null; }

module.exports = { getAppToken, fetchUserPhoto, _resetTokenCache };

